import React, { useState, useEffect } from "react";
import "./App.css";

// Available fraction blocks
const FRACTIONS = [
  { numerator: 1, denominator: 2, color: "#60A5FA", label: "1/2" },
  { numerator: 1, denominator: 3, color: "#34D399", label: "1/3" },
  { numerator: 1, denominator: 4, color: "#F87171", label: "1/4" },
  { numerator: 1, denominator: 6, color: "#FBBF24", label: "1/6" },
  { numerator: 1, denominator: 8, color: "#A78BFA", label: "1/8" },
];

// --- COMPONENT: FREE PLAY ---
function FreePlay() {
  const [rows, setRows] = useState([[], [], []]);

  const handleDragStart = (e, fraction) => e.dataTransfer.setData("fraction", JSON.stringify(fraction));
  const handleDragOver = (e) => e.preventDefault();

  const handleDrop = (e, rowIndex) => {
    e.preventDefault();
    const fractionData = e.dataTransfer.getData("fraction");
    if (fractionData) {
      const fraction = JSON.parse(fractionData);
      const currentTotal = rows[rowIndex].reduce((sum, f) => sum + f.numerator / f.denominator, 0);
      const incomingValue = fraction.numerator / fraction.denominator;

      if (currentTotal + incomingValue <= 1.01) {
        const newRows = [...rows];
        newRows[rowIndex].push({ ...fraction, id: Math.random() });
        setRows(newRows);
      } else {
        alert("Oops! That piece is too big to fit in this row!");
      }
    }
  };

  const removeBlock = (rowIndex, blockIndex) => {
    const newRows = [...rows];
    newRows[rowIndex].splice(blockIndex, 1);
    setRows(newRows);
  };

  return (
    <div className="card">
      <p className="instruction-text">
        Drag the colorful blocks into the empty rows. Can you make two rows exactly the same length?
      </p>

      <div className="toolbox">
        {FRACTIONS.map((frac, index) => (
          <div 
            key={index} 
            draggable 
            onDragStart={(e) => handleDragStart(e, frac)}
            className="fraction-block"
            style={{ backgroundColor: frac.color }}
          >
            {frac.label}
          </div>
        ))}
      </div>

      <div className="row-container">
        <strong className="row-label">This is 1 Whole:</strong>
        <div className="whole-bar">1 Whole</div>
      </div>

      {rows.map((row, rowIndex) => (
        <div key={rowIndex} className="row-container">
          <strong className="row-label">Row {rowIndex + 1}:</strong>
          <div onDragOver={handleDragOver} onDrop={(e) => handleDrop(e, rowIndex)} className="drop-zone">
            {row.length === 0 && <span className="drop-zone-placeholder">Drag blocks here!</span>}
            {row.map((block, blockIndex) => (
              <div 
                key={block.id} 
                onClick={() => removeBlock(rowIndex, blockIndex)} 
                className="placed-block"
                style={{ width: `${(block.numerator / block.denominator) * 100}%`, backgroundColor: block.color }}
              >
                {block.label}
              </div>
            ))}
          </div>
        </div>
      ))}
      <div style={{ textAlign: "center", marginTop: "20px" }}>
        <button onClick={() => setRows([[], [], []])} className="btn-danger">🗑️ Clear Board</button>
      </div>
    </div>
  );
}

// --- COMPONENT: PIZZA MODE ---
function PizzaMode() {
  const [slices, setSlices] = useState([]);

  const handleDragStart = (e, fraction) => e.dataTransfer.setData("fraction", JSON.stringify(fraction));
  const handleDragOver = (e) => e.preventDefault();

  const handleDrop = (e) => {
    e.preventDefault();
    const fractionData = e.dataTransfer.getData("fraction");
    if (fractionData) {
      const fraction = JSON.parse(fractionData);
      const currentTotal = slices.reduce((sum, f) => sum + f.numerator / f.denominator, 0);
      const incomingValue = fraction.numerator / fraction.denominator;

      if (currentTotal + incomingValue <= 1.01) {
        setSlices([...slices, { ...fraction, id: Math.random() }]);
      } else {
        alert("Wait! The pizza is full!");
      }
    }
  };

  let currentAngle = -90; // Start at top

  return (
    <div className="card">
      <p className="instruction-text">Build your own pizza! Drag fraction slices to the tray. 🍕</p>

      <div className="toolbox">
        {FRACTIONS.map((frac, index) => (
          <div key={index} draggable onDragStart={(e) => handleDragStart(e, frac)}
            className="fraction-block" style={{ backgroundColor: frac.color }}>{frac.label}</div>
        ))}
      </div>

      <div className="pizza-container" onDragOver={handleDragOver} onDrop={handleDrop}>
        <svg width="300" height="300" viewBox="0 0 100 100" className="pizza-svg">
          {/* Pizza Tray */}
          <circle cx="50" cy="50" r="48" fill="#FDE68A" stroke="#D97706" strokeWidth="2" />
          <circle cx="50" cy="50" r="42" fill="#FEF3C7" />

          {/* Slices */}
          {slices.map((slice) => {
            const angle = (slice.numerator / slice.denominator) * 360;
            const x1 = 50 + 40 * Math.cos((currentAngle * Math.PI) / 180);
            const y1 = 50 + 40 * Math.sin((currentAngle * Math.PI) / 180);
            currentAngle += angle;
            const x2 = 50 + 40 * Math.cos((currentAngle * Math.PI) / 180);
            const y2 = 50 + 40 * Math.sin((currentAngle * Math.PI) / 180);

            const largeArcFlag = angle > 180 ? 1 : 0;
            const d = `M 50 50 L ${x1} ${y1} A 40 40 0 ${largeArcFlag} 1 ${x2} ${y2} Z`;

            return (
              <path 
                key={slice.id} 
                d={d} 
                fill={slice.color} 
                stroke="white" 
                strokeWidth="0.5"
                className="pizza-slice"
                onClick={() => setSlices(slices.filter(s => s.id !== slice.id))}
              />
            );
          })}
        </svg>
        <button onClick={() => setSlices([])} className="btn-danger">New Pizza</button>
      </div>
    </div>
  );
}

// --- COMPONENT: JOURNEY MODE ---
function JourneyMode() {
  const [journey, setJourney] = useState([]);
  const [vehicle, setVehicle] = useState("🚗");

  const totalDistance = journey.reduce((sum, f) => sum + f.numerator / f.denominator, 0);

  const handleDragStart = (e, fraction) => e.dataTransfer.setData("fraction", JSON.stringify(fraction));
  const handleDragOver = (e) => e.preventDefault();

  const handleDrop = (e) => {
    e.preventDefault();
    const fractionData = e.dataTransfer.getData("fraction");
    if (fractionData) {
      const fraction = JSON.parse(fractionData);
      if (totalDistance + (fraction.numerator / fraction.denominator) <= 1.01) {
        setJourney([...journey, { ...fraction, id: Math.random() }]);
      } else {
        alert("You reached the destination!");
      }
    }
  };

  return (
    <div className="card">
      <p className="instruction-text">Help the vehicle reach the finish line! Drag distances to move. 🏁</p>

      <div style={{ textAlign: 'center', marginBottom: '1rem', fontSize: '2rem' }}>
        {['🚗', '🚲', '🏃', '🚀', '🛸'].map(v => (
          <span key={v} onClick={() => setVehicle(v)} style={{ cursor: 'pointer', margin: '0 10px', opacity: vehicle === v ? 1 : 0.3 }}>{v}</span>
        ))}
      </div>

      <div className="toolbox">
        {FRACTIONS.map((frac, index) => (
          <div key={index} draggable onDragStart={(e) => handleDragStart(e, frac)}
            className="fraction-block" style={{ backgroundColor: frac.color }}>{frac.label}</div>
        ))}
      </div>

      <div className="journey-road" onDragOver={handleDragOver} onDrop={handleDrop}>
        <div className="road-markings"></div>
        <div className="finish-line"></div>

        {/* Progress path */}
        {journey.map((step) => (
          <div 
            key={step.id} 
            style={{ 
              height: '100%', 
              width: `${(step.numerator / step.denominator) * 100}%`, 
              backgroundColor: step.color,
              opacity: 0.6,
              borderRight: '2px solid white'
            }}
          />
        ))}

        <div className="vehicle" style={{ left: `${Math.min(totalDistance * 100, 100)}%` }}>
          {vehicle}
        </div>
      </div>

      <div style={{ textAlign: "center" }}>
        <button onClick={() => setJourney([])} className="btn-danger">Restart Journey</button>
      </div>
    </div>
  );
}

// --- COMPONENT: FRACTION WALL ---
function FractionWall() {
  const rows = [
    [{ n: 1, d: 1, label: "1 Whole", color: "#94A3B8" }],
    [{ n: 1, d: 2, label: "1/2", color: "#60A5FA" }, { n: 1, d: 2, label: "1/2", color: "#60A5FA" }],
    [{ n: 1, d: 3, label: "1/3", color: "#34D399" }, { n: 1, d: 3, label: "1/3", color: "#34D399" }, { n: 1, d: 3, label: "1/3", color: "#34D399" }],
    Array(4).fill({ n: 1, d: 4, label: "1/4", color: "#F87171" }),
    Array(6).fill({ n: 1, d: 6, label: "1/6", color: "#FBBF24" }),
    Array(8).fill({ n: 1, d: 8, label: "1/8", color: "#A78BFA" }),
  ];

  return (
    <div className="card">
      <p className="instruction-text">The Fraction Wall shows how one whole can be broken into many pieces!</p>
      <div className="fraction-wall">
        {rows.map((row, i) => (
          <div key={i} className="wall-row">
            {row.map((block, j) => (
              <div 
                key={j} 
                className="wall-block" 
                style={{ 
                  width: `${(block.n / block.d) * 100}%`, 
                  backgroundColor: block.color 
                }}
              >
                {block.label}
              </div>
            ))}
          </div>
        ))}
      </div>
    </div>
  );
}

